#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding genetic-assessment (17 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    primary_language:string! \
    interpreter_required:string! \
    marital_status:string! \
    occupation:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    --htmx

cargo loco generate scaffold assessment_referral_information \
    assessment:references \
    referring_clinician_name:string! \
    referring_clinician_role:string! \
    referring_organisation:string! \
    referral_date:date \
    referral_reason:text! \
    referral_urgency:string! \
    specialty_referred_to:string! \
    previous_genetic_referral:string! \
    previous_referral_details:text! \
    --htmx

cargo loco generate scaffold assessment_personal_medical_history \
    assessment:references \
    has_cancer_diagnosis:string! \
    cancer_type:string! \
    cancer_age_at_diagnosis:int \
    cancer_treatment_details:text! \
    has_cardiovascular_condition:string! \
    cardiovascular_details:text! \
    has_neurological_condition:string! \
    neurological_details:text! \
    has_congenital_anomalies:string! \
    congenital_anomaly_details:text! \
    has_intellectual_disability:string! \
    intellectual_disability_details:text! \
    other_significant_conditions:text! \
    --htmx

cargo loco generate scaffold assessment_cancer_history \
    assessment:references \
    family_cancer_history:string! \
    multiple_family_cancers:string! \
    early_onset_cancer:string! \
    bilateral_cancer:string! \
    rare_tumour_types:string! \
    rare_tumour_details:text! \
    known_cancer_syndrome:string! \
    cancer_syndrome_details:text! \
    cancer_risk_score:int \
    --htmx

cargo loco generate scaffold assessment_cancer_history_item \
    cancer_history:references \
    relative_relationship:string! \
    cancer_type:string! \
    age_at_diagnosis:int \
    outcome:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_family_pedigree \
    assessment:references \
    total_first_degree_relatives:int \
    total_second_degree_relatives:int \
    consanguinity_in_family:string! \
    consanguinity_details:text! \
    adoption_status:string! \
    pedigree_notes:text! \
    three_generation_pedigree_drawn:string! \
    --htmx

cargo loco generate scaffold assessment_family_pedigree_member \
    family_pedigree:references \
    relationship:string! \
    sex:string! \
    age:int \
    alive:string! \
    age_at_death:int \
    cause_of_death:string! \
    medical_conditions:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_genetics \
    assessment:references \
    family_history_sudden_cardiac_death:string! \
    sudden_cardiac_death_details:text! \
    family_history_cardiomyopathy:string! \
    cardiomyopathy_type:string! \
    cardiomyopathy_details:text! \
    family_history_aortopathy:string! \
    aortopathy_details:text! \
    family_history_arrhythmia:string! \
    arrhythmia_type:string! \
    family_history_familial_hypercholesterolaemia:string! \
    cholesterol_level_mmol_l:double \
    connective_tissue_disorder:string! \
    connective_tissue_details:text! \
    cardiovascular_risk_score:int \
    --htmx

cargo loco generate scaffold assessment_neurogenetics \
    assessment:references \
    family_history_huntington:string! \
    huntington_details:text! \
    family_history_early_onset_dementia:string! \
    dementia_type:string! \
    dementia_age_at_onset:int \
    family_history_motor_neurone_disease:string! \
    motor_neurone_details:text! \
    family_history_hereditary_neuropathy:string! \
    hereditary_neuropathy_details:text! \
    family_history_epilepsy:string! \
    epilepsy_details:text! \
    family_history_ataxia:string! \
    ataxia_details:text! \
    neurogenetics_risk_score:int \
    --htmx

cargo loco generate scaffold assessment_reproductive_genetics \
    assessment:references \
    planning_pregnancy:string! \
    currently_pregnant:string! \
    gestational_age_weeks:int \
    history_of_recurrent_miscarriage:string! \
    number_of_miscarriages:int \
    history_of_stillbirth:string! \
    stillbirth_details:text! \
    history_of_neonatal_death:string! \
    neonatal_death_details:text! \
    child_with_congenital_anomaly:string! \
    congenital_anomaly_details:text! \
    known_carrier_status:string! \
    carrier_status_details:text! \
    partner_carrier_status:string! \
    partner_carrier_details:text! \
    assisted_reproduction:string! \
    assisted_reproduction_details:text! \
    --htmx

cargo loco generate scaffold assessment_ethnic_background_and_consanguinity \
    assessment:references \
    maternal_ethnic_background:string! \
    paternal_ethnic_background:string! \
    maternal_country_of_origin:string! \
    paternal_country_of_origin:string! \
    ashkenazi_jewish_ancestry:string! \
    ashkenazi_lineage:string! \
    consanguinity:string! \
    consanguinity_degree:string! \
    endogamous_community:string! \
    endogamous_community_details:text! \
    population_specific_conditions:text! \
    --htmx

cargo loco generate scaffold assessment_genetic_testing_history \
    assessment:references \
    previous_genetic_testing:string! \
    previous_chromosomal_analysis:string! \
    chromosomal_analysis_result:text! \
    previous_single_gene_test:string! \
    single_gene_test_details:text! \
    previous_gene_panel:string! \
    gene_panel_details:text! \
    previous_whole_exome_sequencing:string! \
    wes_result:text! \
    previous_whole_genome_sequencing:string! \
    wgs_result:text! \
    previous_microarray:string! \
    microarray_result:text! \
    prenatal_testing_performed:string! \
    prenatal_testing_details:text! \
    family_member_testing:string! \
    family_member_testing_details:text! \
    consent_for_further_testing:string! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    risk_level:string! \
    total_risk_score:int! \
    cancer_genetics_score:int! \
    cardiovascular_genetics_score:int! \
    neurogenetics_score:int! \
    reproductive_genetics_score:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    risk_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
